module RefModule(Clock, Resetn, w, z);input Clock, Resetn, w; 
  output z; 
  reg [1:0] y, Y; 
  parameter [1:0] A = 2'b00, B = 2'b01, C = 2'b10; 


  always @(w or y) 
    case (y) 
      A:  if (w)    Y = B; 
        else    Y = A; 
      B:  if (w)    Y = C; 
        else    Y = A; 
      C:  if (w)    Y = C; 
        else    Y = A; 
      default:      Y = 2'b00; 
    endcase 


  always @(posedge Clock) 
    if (Resetn == 1'b0) y <= A; 
    else y <= Y; 


    wire _n01 = y[0] ^ C[0];
  wire _n02 = y[1] ^ C[1];
  wire _n03 = y[2] ^ C[2];
  wire _n04 = y[3] ^ C[3];
  assign z = ~_n01 & ~_n02 & ~_n03 & ~_n04; 

endmodule
